1	import { Request, Response, NextFunction } from 'express';
2	import { z } from 'zod';
3	import * as authService from '../services/auth.service';
4	
5	export const registerSchema = z.object({
6	  username: z.string().min(3).max(50).trim(),
7	  email: z.string().email().trim().toLowerCase(),
8	  password: z.string().min(8).max(128),
9	  role: z.enum(['alumni', 'photographer', 'admin']).optional(),
10	});
11	
12	export const loginSchema = z.object({
13	  username: z.string().min(1).optional(),
14	  email: z.string().optional(),
15	  password: z.string().min(1),
16	});
17	
18	export async function register(req: Request, res: Response, next: NextFunction): Promise<void> {
19	  try {
20	    const result = await authService.register(req.body);
21	    res.status(201).json(result);
22	  } catch (err) {
23	    next(err);
24	  }
