1	import { User, Profile, Session } from '../models';
2	import { Role, AccountStatus } from '../types/enums';
3	import { AuthError, ValidationError, ForbiddenError, ConflictError } from '../utils/errors';
4	import { issueToken } from './token.service';
5	import { logEvent } from './audit.service';
6	import { AUDIT_EVENTS } from '../utils/constants';
7	
8	export interface RegisterInput {
9	  username: string;
10	  email: string;
11	  password: string;
12	  role?: Role;
13	  isAlumni?: boolean;
14	  communityId?: string;
15	  firstName?: string;
16	  lastName?: string;
17	}
18	
19	export interface LoginInput {
20	  email: string;
21	  password: string;
22	  ipAddress?: string;
23	  deviceFingerprint?: string;
24	}
25	
26	export async function register(input: RegisterInput) {
27	  // Validate password strength
28	  if (!input.password || input.password.length < 8) {
29	    throw new ValidationError('Password must be at least 8 characters');
30	  }
31	  if (!/[A-Z]/.test(input.password)) {
32	    throw new ValidationError('Password must contain an uppercase letter');
33	  }
34	  if (!/[a-z]/.test(input.password)) {
35	    throw new ValidationError('Password must contain a lowercase letter');
36	  }
37	  if (!/[0-9]/.test(input.password)) {
38	    throw new ValidationError('Password must contain a number');
39	  }
40	
41	  const existingUser = await User.findOne({
42	    $or: [{ email: input.email.toLowerCase() }, { username: input.username }],
43	  });
44	
45	  if (existingUser) {
46	    throw new ConflictError('A user with that email or username already exists');
47	  }
48	
49	  const user = await User.create({
50	    username: input.username,
51	    email: input.email.toLowerCase(),
52	    passwordHash: input.password,
53	    role: input.role || Role.ALUMNI,
54	    isAlumni: input.isAlumni !== undefined ? input.isAlumni : true,
55	    communityId: input.communityId || 'default',
56	  });
57	
58	  const profile = await Profile.create({
59	    userId: user._id,
60	    firstName: input.firstName || '',
61	    lastName: input.lastName || '',
62	    email: input.email.toLowerCase(),
63	  });
64	
65	  const { token, jti, expiresAt } = issueToken(user._id!.toString(), user.role);
66	  await Session.create({
67	    userId: user._id,
68	    jti,
69	    issuedAt: new Date(),
70	    lastActivityAt: new Date(),
71	    absoluteExpiry: expiresAt,
72	  });
73	
74	  return { user, profile, token };
75	}
76	
77	export async function login(input: any) {
78	  const query = input.username
79	    ? { username: input.username }
80	    : { email: (input.email || '').toLowerCase() };
81	  const user = await User.findOne(query);
82	
83	  if (!user) {
84	    await logEvent({
85	      action: AUDIT_EVENTS.LOGIN_FAILURE,
86	      resource: 'auth',
87	      details: { email: input.email, reason: 'user_not_found' },
88	      ipAddress: input.ipAddress,
89	      outcome: 'failure',
90	    });
91	    throw new AuthError('Invalid email or password');
92	  }
93	
94	  if (user.accountStatus === AccountStatus.BANNED) {
95	    await logEvent({
96	      actorId: user._id.toString(),
97	      actorRole: user.role,
98	      action: AUDIT_EVENTS.LOGIN_FAILURE,
99	      resource: 'auth',
100	      resourceId: user._id.toString(),
101	      details: { reason: 'account_banned' },
102	      ipAddress: input.ipAddress,
103	      outcome: 'failure',
104	    });
105	    throw new ForbiddenError('This account has been banned');
106	  }
107	
108	  if (user.accountStatus === AccountStatus.SUSPENDED) {
109	    await logEvent({
110	      actorId: user._id.toString(),
111	      actorRole: user.role,
112	      action: AUDIT_EVENTS.LOGIN_FAILURE,
113	      resource: 'auth',
114	      resourceId: user._id.toString(),
115	      details: { reason: 'account_suspended' },
116	      ipAddress: input.ipAddress,
117	      outcome: 'failure',
118	    });
119	    throw new ForbiddenError('This account is currently suspended');
120	  }
121	
122	  const isMatch = await user.comparePassword(input.password);
123	  if (!isMatch) {
124	    user.failedLoginAttempts += 1;
125	    await user.save();
126	
127	    await logEvent({
128	      actorId: user._id.toString(),
129	      actorRole: user.role,
130	      action: AUDIT_EVENTS.LOGIN_FAILURE,
131	      resource: 'auth',
132	      resourceId: user._id.toString(),
133	      details: { reason: 'invalid_password', attempts: user.failedLoginAttempts },
134	      ipAddress: input.ipAddress,
135	      outcome: 'failure',
136	    });
137	    throw new AuthError('Invalid email or password');
138	  }
139	
140	  // Successful login — reset failed attempts
141	  user.failedLoginAttempts = 0;
142	  user.lastLoginAt = new Date();
143	  user.lastActivityAt = new Date();
144	  await user.save();
145	
146	  const { token, jti, expiresAt } = issueToken(user._id.toString(), user.role);
147	
148	  const session = await Session.create({
149	    userId: user._id,
150	    jti,
151	    deviceFingerprint: input.deviceFingerprint,
152	    issuedAt: new Date(),
153	    lastActivityAt: new Date(),
154	    absoluteExpiry: expiresAt,
155	  });
156	
157	  await logEvent({
158	    actorId: user._id.toString(),
159	    actorRole: user.role,
160	    action: AUDIT_EVENTS.LOGIN_SUCCESS,
161	    resource: 'auth',
162	    resourceId: user._id.toString(),
163	    ipAddress: input.ipAddress,
164	    deviceFingerprint: input.deviceFingerprint,
165	    outcome: 'success',
166	  });
167	
168	  return { user, token, session };
169	}
170	
171	export async function logout(jti: string, userId?: string): Promise<void> {
172	  const session = await Session.findOne({ jti, isRevoked: false });
173	  if (!session) {
174	    return; // Already revoked or doesn't exist — idempotent
175	  }
176	
177	  session.isRevoked = true;
178	  session.revokedAt = new Date();
179	  await session.save();
180	}
