3	import { Settlement, SettlementLineItem, User } from '../models';
4	import { AuditLog } from '../models/AuditLog';
5	import { Blacklist } from '../models/Blacklist';
6	import { ForbiddenError, NotFoundError } from '../utils/errors';
7	import { formatCentsToUSD } from '../utils/money';
8	import { AUDIT_EVENTS } from '../utils/constants';
9	import { beforeExport } from '../hooks/complianceHooks';
10	import { BlacklistTargetType, AccountStatus } from '../types/enums';
11	
12	async function checkExportPermissions(userId: string): Promise<void> {
13	  const user = await User.findById(userId);
14	  if (!user || user.accountStatus === AccountStatus.BANNED || user.isBlacklisted) {
15	    await AuditLog.create({
16	      timestamp: new Date(), actorId: userId, action: AUDIT_EVENTS.EXPORT_BLOCKED,
17	      resource: 'settlement', outcome: 'failure', details: { reason: 'banned or blacklisted' },
18	    });
19	    throw new ForbiddenError('Export blocked for banned or blacklisted accounts');
20	  }
21	  const bl = await Blacklist.findOne({ targetType: BlacklistTargetType.ACCOUNT, targetId: userId });
22	  if (bl) {
23	    await AuditLog.create({
24	      timestamp: new Date(), actorId: userId, action: AUDIT_EVENTS.EXPORT_BLOCKED,
25	      resource: 'settlement', outcome: 'failure',
26	    });
27	    throw new ForbiddenError('Export blocked');
28	  }
29	  const hookResult = await beforeExport({ userId, resourceType: 'settlement' });
30	  if (!hookResult.allow) throw new ForbiddenError(hookResult.reason || 'Export blocked by compliance');
31	}
32	
33	export async function exportSettlementPDF(settlementId: string, userId: string, userRole?: string): Promise<Buffer> {
34	  await checkExportPermissions(userId);
35	  const settlement = await Settlement.findById(settlementId);
36	  if (!settlement) throw new NotFoundError('Settlement not found');
37	
38	  // Strict access: only job participants or admins may export
39	  if (userRole !== 'admin') {
40	    const isParticipant =
41	      settlement.clientId.toString() === userId ||
42	      settlement.photographerId.toString() === userId;
43	    if (!isParticipant) {
44	      await AuditLog.create({
45	        timestamp: new Date(), actorId: userId, action: AUDIT_EVENTS.ACCESS_DENIED,
46	        resource: 'settlement', resourceId: settlementId, outcome: 'failure',
47	        details: { reason: 'not_a_participant' },
48	      });
49	      throw new ForbiddenError('Only job participants or admins can export settlements');
50	    }
51	  }
52	
53	  const lineItems = await SettlementLineItem.find({ settlementId });
54	
55	  return new Promise((resolve, reject) => {
56	    const doc = new PDFDocument({ margin: 50 });
57	    const chunks: Buffer[] = [];
58	    doc.on('data', (chunk: Buffer) => chunks.push(chunk));
59	    doc.on('end', async () => {
60	      const buffer = Buffer.concat(chunks);
61	      await AuditLog.create({
62	        timestamp: new Date(), actorId: userId, action: AUDIT_EVENTS.DATA_EXPORT,
63	        resource: 'settlement', resourceId: settlementId, outcome: 'success', details: { format: 'pdf' },
64	      });
65	      resolve(buffer);
66	    });
67	    doc.on('error', reject);
68	
69	    doc.fontSize(20).text('Settlement Statement', { align: 'center' });
70	    doc.moveDown();
71	    doc.fontSize(12).text(`Settlement ID: ${settlementId}`);
72	    doc.text(`Status: ${settlement.status}`);
73	    doc.text(`Subtotal: ${formatCentsToUSD(settlement.subtotalCents)}`);
74	    doc.text(`Adjustments: ${formatCentsToUSD(settlement.adjustmentCents)}`);
75	    doc.text(`Final Amount: ${formatCentsToUSD(settlement.finalAmountCents)}`);
76	    if (settlement.varianceReason) doc.text(`Variance Reason: ${settlement.varianceReason}`);
77	    doc.moveDown();
78	    doc.fontSize(14).text('Line Items');
79	    doc.moveDown();
80	    for (const item of lineItems) {
81	      doc.fontSize(10).text(`${item.description}: ${formatCentsToUSD(item.amountCents)} (${item.type})`);
82	    }
83	    doc.end();
84	  });
85	}
