87	export async function exportSettlementCSV(settlementId: string, userId: string, userRole?: string): Promise<Buffer> {
88	  await checkExportPermissions(userId);
89	  const settlement = await Settlement.findById(settlementId);
90	  if (!settlement) throw new NotFoundError('Settlement not found');
91	
92	  // Strict access: only job participants or admins may export
93	  if (userRole !== 'admin') {
94	    const isParticipant =
95	      settlement.clientId.toString() === userId ||
96	      settlement.photographerId.toString() === userId;
97	    if (!isParticipant) {
98	      await AuditLog.create({
99	        timestamp: new Date(), actorId: userId, action: AUDIT_EVENTS.ACCESS_DENIED,
100	        resource: 'settlement', resourceId: settlementId, outcome: 'failure',
101	        details: { reason: 'not_a_participant' },
102	      });
103	      throw new ForbiddenError('Only job participants or admins can export settlements');
104	    }
105	  }
106	
107	  const lineItems = await SettlementLineItem.find({ settlementId });
108	
109	  const rows: Record<string, string>[] = lineItems.map(item => ({
110	    description: item.description,
111	    amount: formatCentsToUSD(item.amountCents),
112	    type: item.type as string,
113	    adjustmentType: (item.adjustmentType || '') as string,
114	    adjustmentReason: item.adjustmentReason || '',
115	  }));
116	  rows.push({ description: 'TOTAL', amount: formatCentsToUSD(settlement.finalAmountCents), type: '', adjustmentType: '', adjustmentReason: '' });
117	
118	  const csv = stringify(rows, { header: true });
119	  await AuditLog.create({
120	    timestamp: new Date(), actorId: userId, action: AUDIT_EVENTS.DATA_EXPORT,
121	    resource: 'settlement', resourceId: settlementId, outcome: 'success', details: { format: 'csv' },
122	  });
123	  return Buffer.from(csv);
124	}
