1	import { Request, Response, NextFunction } from 'express';
2	import { Nonce } from '../models/Nonce';
3	import { config } from '../config';
4	import { ConflictError, ValidationError } from '../utils/errors';
5	
6	const NONCE_EXEMPT_PATHS = [
7	  'GET:/api/health',
8	];
9	
10	export async function nonceReplay(req: Request, _res: Response, next: NextFunction): Promise<void> {
11	  try {
12	    const routeKey = `${req.method}:${req.path}`;
13	    if (NONCE_EXEMPT_PATHS.includes(routeKey)) {
14	      return next();
15	    }
16	
17	    const nonce = req.headers['x-nonce'] as string;
18	    const timestamp = req.headers['x-timestamp'] as string;
19	
20	    if (!nonce || !timestamp) {
21	      return next(new ValidationError('X-Nonce and X-Timestamp headers are required'));
22	    }
23	
24	    const requestTime = parseInt(timestamp, 10);
25	    if (isNaN(requestTime)) {
26	      return next(new ValidationError('Invalid X-Timestamp header'));
27	    }
28	
29	    const now = Date.now();
30	    const diff = Math.abs(now - requestTime);
31	
32	    if (diff > config.nonceWindowMs + config.clockSkewMs) {
33	      return next(new ValidationError('Request timestamp outside acceptable window'));
34	    }
35	
36	    const existing = await Nonce.findOne({ nonce });
37	    if (existing) {
38	      return next(new ConflictError('Duplicate nonce detected - possible replay attack'));
39	    }
40	
41	    await Nonce.create({ nonce, timestamp: new Date(requestTime) });
42	    req.nonce = nonce;
43	    next();
44	  } catch (err) {
45	    next(err);
46	  }
47	}
