73	export async function addAdjustment(
74	  settlementId: string,
75	  adjustmentType: AdjustmentType,
76	  amountCents: number,
77	  reason: string,
78	  createdBy: string
79	) {
80	  if (!reason || reason.trim().length === 0) {
81	    throw new ValidationError('Adjustment reason is required');
82	  }
83	
84	  const settlement = await Settlement.findById(settlementId);
85	  if (!settlement) {
86	    throw new NotFoundError('Settlement not found');
87	  }
88	
89	  if (settlement.status !== SettlementStatus.DRAFT && settlement.status !== SettlementStatus.PENDING_REVIEW) {
90	    throw new ValidationError(`Cannot add adjustments to a settlement with status: ${settlement.status}`);
91	  }
92	
93	  const description = `${adjustmentType}: ${reason}`;
94	
95	  const lineItem = await SettlementLineItem.create({
96	    settlementId,
97	    description,
98	    amountCents,
99	    type: LineItemType.ADJUSTMENT,
100	    adjustmentType,
101	    adjustmentReason: reason,
102	    createdBy,
103	  });
104	
105	  // Recalculate settlement totals
106	  settlement.adjustmentCents = addCents(settlement.adjustmentCents, amountCents);
107	  settlement.finalAmountCents = addCents(settlement.subtotalCents, settlement.adjustmentCents);
108	
109	  // Run variance check: threshold = max(subtotal * 0.02, 2500)
110	  const variance = varianceCheck(settlement.subtotalCents, settlement.finalAmountCents);
111	  settlement.variancePercent = variance.variancePercent;
112	  settlement.varianceAmountCents = variance.varianceAmountCents;
113	
114	  await settlement.save();
115	
116	  return { settlement, lineItem };
117	}
