43	export async function getJobById(jobId: string, requesterId?: string, requesterRole?: string) {
44	  const job = await Job.findById(jobId);
45	  if (!job) {
46	    throw new NotFoundError('Job not found');
47	  }
48	  // Object-level authorization: participants, community members with posted jobs, or admins
49	  if (requesterId && requesterRole !== Role.ADMIN) {
50	    const isParticipant = job.clientId.toString() === requesterId ||
51	      (job.photographerId && job.photographerId.toString() === requesterId);
52	    const isPublicStatus = [JobStatus.POSTED].includes(job.status as JobStatus);
53	    if (!isParticipant && !isPublicStatus) {
54	      throw new ForbiddenError('You do not have access to this job');
