60	export async function updateJob(jobId: string, userId: string, data: Partial<IJob>) {
61	  const job = await Job.findById(jobId);
62	  if (!job) {
63	    throw new NotFoundError('Job not found');
64	  }
65	
66	  if (job.clientId.toString() !== userId) {
67	    throw new ForbiddenError('Only the job client can update the job');
68	  }
69	
70	  if (job.status !== JobStatus.DRAFT && job.status !== JobStatus.POSTED) {
71	    throw new ValidationError('Can only update jobs in draft or posted status');
72	  }
73	
74	  Object.assign(job, data);
75	  await job.save();
76	  return job;
