15	  const [actionLoading, setActionLoading] = useState('');
16	
17	  const fetchData = async () => {
18	    try {
19	      const [histRes, catRes, polRes] = await Promise.all([
20	        consentApi.getHistory(),
21	        consentApi.getCategoryConsents(),
22	        consentApi.getCurrentPolicy().catch(() => ({ data: null })),
23	      ]);
24	      setHistory(histRes.data.items || histRes.data || []);
25	      setCategories(catRes.data.items || catRes.data || []);
26	      setCurrentPolicy(polRes.data);
27	    } catch (err: any) {
28	      setError(err.response?.data?.msg || 'Failed to load consent data');
29	    } finally {
30	      setLoading(false);
31	    }
32	  };
33	
34	  useEffect(() => { fetchData(); }, []);
35	
36	  const handleGrantConsent = async (category: string) => {
37	    setActionLoading(category);
38	    try {
39	      await consentApi.recordCategoryConsent({ category });
40	      await fetchData();
41	    } catch (err: any) {
42	      setError(err.response?.data?.msg || 'Failed to grant consent');
43	    } finally {
44	      setActionLoading('');
45	    }
46	  };
47	
48	  const handleRevoke = async (category: string) => {
49	    if (!confirm(`Revoke consent for ${category.replace(/_/g, ' ')}?`)) return;
50	    setActionLoading(category);
51	    try {
52	      await consentApi.revokeCategoryConsent(category);
53	      await fetchData();
54	    } catch (err: any) {
55	      setError(err.response?.data?.msg || 'Failed to revoke consent');
56	    } finally {
57	      setActionLoading('');
58	    }
59	  };
60	
61	  const handleAcceptPolicy = async () => {
62	    if (!currentPolicy) return;
63	    setActionLoading('policy');
64	    try {
65	      await consentApi.recordConsent({ policyId: currentPolicy._id });
66	      await fetchData();
67	    } catch (err: any) {
68	      setError(err.response?.data?.msg || 'Failed to record consent');
69	    } finally {
70	      setActionLoading('');
71	    }
72	  };
73	
74	  if (loading) return <LoadingSpinner message="Loading consent data..." />;
75	
76	  const consentedCategories = new Set(categories.map((c: any) => c.category));
