1	import { Request, Response, NextFunction } from 'express';
2	import jwt from 'jsonwebtoken';
3	import { config } from '../config';
4	import { Session } from '../models/Session';
5	import { User } from '../models/User';
6	import { AuthError } from '../utils/errors';
7	import { AccountStatus } from '../types/enums';
8	
9	const PUBLIC_PATHS = [
10	  'POST:/api/auth/register',
11	  'POST:/api/auth/login',
12	  'GET:/api/health',
13	];
14	
15	export async function authenticate(req: Request, _res: Response, next: NextFunction): Promise<void> {
16	  const routeKey = `${req.method}:${req.path}`;
17	  if (PUBLIC_PATHS.includes(routeKey)) {
18	    return next();
19	  }
20	
21	  try {
22	    const authHeader = req.headers.authorization;
23	    if (!authHeader?.startsWith('Bearer ')) {
24	      return next(new AuthError('Missing or invalid authorization header'));
25	    }
26	
27	    const token = authHeader.slice(7);
28	    let payload: any;
29	    try {
30	      payload = jwt.verify(token, config.jwtSecret);
31	    } catch {
32	      return next(new AuthError('Invalid or expired token'));
33	    }
34	
35	    const session = await Session.findOne({ jti: payload.jti });
36	    if (!session || session.isRevoked) {
37	      return next(new AuthError('Session revoked or expired'));
38	    }
39	
40	    const now = new Date();
41	    if (now > session.absoluteExpiry) {
42	      return next(new AuthError('Session expired'));
43	    }
44	
45	    const idleMs = now.getTime() - session.lastActivityAt.getTime();
46	    if (idleMs > config.idleTimeoutMs) {
47	      return next(new AuthError('Session idle timeout'));
48	    }
49	
50	    const user = await User.findById(payload.userId);
51	    if (!user || user.accountStatus !== AccountStatus.ACTIVE) {
52	      return next(new AuthError('Account not active'));
53	    }
54	
55	    session.lastActivityAt = now;
56	    await session.save();
57	
58	    req.user = {
59	      userId: payload.userId,
60	      role: user.role,
61	      sessionId: session._id!.toString(),
62	      isAlumni: user.isAlumni,
63	      communityId: user.communityId,
64	      accountStatus: user.accountStatus,
65	    };
66	
67	    next();
68	  } catch (err) {
69	    next(err);
70	  }
71	}
