17	      res.status(400).json({ code: 400, msg: 'No documents uploaded' });
18	      return;
19	    }
20	    // Handle both multer.fields() and multer.array() upload patterns
21	    let allFiles: Express.Multer.File[] = [];
22	    if (Array.isArray(req.files)) {
23	      allFiles = req.files;
24	    } else if (req.files && typeof req.files === 'object') {
25	      const fileMap = req.files as { [fieldname: string]: Express.Multer.File[] };
26	      for (const field of Object.values(fileMap)) {
27	        allFiles.push(...field);
28	      }
29	    }
30	    // Use file service to store files from memory buffers
31	    const { saveFile } = await import('../services/file.service');
32	    const storedPaths: string[] = [];
33	    const checksums: string[] = [];
34	    for (const file of allFiles) {
35	      const stored = await saveFile({
36	        buffer: file.buffer,
37	        originalName: file.originalname,
38	        mimeType: file.mimetype,
39	        parentType: 'verification',
40	        parentId: req.user!.userId,
41	        uploadedBy: req.user!.userId,
42	      });
43	      storedPaths.push(stored.storagePath);
44	      checksums.push(stored.checksum);
45	    }
46	    const result = await verificationService.submitVerification({
47	      photographerId: req.user!.userId,
48	      realName: req.body.realName || req.body.documentType || 'Not provided',
49	      qualificationType: req.body.qualificationType || req.body.documentType || 'general',
50	      issuingAuthority: req.body.issuingAuthority,
51	      idDocumentPath: storedPaths[0] || '',
52	      qualificationDocPaths: storedPaths.slice(1),
53	      fileChecksums: checksums,
54	    });
55	    res.status(201).json(result);
56	  } catch (err) {
57	    next(err);
58	  }
59	}
