1	import { Settlement, SettlementLineItem, WorkEntry, Job } from '../models';
2	import { SettlementStatus, LineItemType, AdjustmentType, WorkEntryType } from '../types/enums';
3	import { NotFoundError, ValidationError, ForbiddenError } from '../utils/errors';
4	import { addCents, varianceCheck } from '../utils/money';
5	import { beforeSettlementFinalize } from '../hooks/complianceHooks';
6	
7	/**
8	 * Generate a settlement by aggregating locked work entries for a job.
9	 */
10	export async function generateSettlement(jobId: string, generatedBy: string) {
11	  const job = await Job.findById(jobId);
12	  if (!job) {
13	    throw new NotFoundError('Job not found');
14	  }
15	
16	  if (!job.photographerId) {
17	    throw new ValidationError('Job has no assigned photographer');
18	  }
19	
20	  // Get locked work entries
21	  const entries = await WorkEntry.find({ jobId, isLocked: true }).lean();
22	
23	  if (entries.length === 0) {
24	    throw new ValidationError('No locked work entries to settle');
25	  }
26	
27	  // Calculate subtotal
28	  let subtotalCents = 0;
29	  for (const entry of entries) {
30	    subtotalCents = addCents(subtotalCents, entry.subtotalCents);
31	  }
32	
33	  const settlement = await Settlement.create({
34	    jobId,
35	    photographerId: job.photographerId,
36	    clientId: job.clientId,
37	    status: SettlementStatus.DRAFT,
38	    subtotalCents,
39	    adjustmentCents: 0,
40	    finalAmountCents: subtotalCents,
41	  });
42	
43	  // Create line items for each work entry
44	  const lineItems = [];
45	  for (const entry of entries) {
46	    const lineItemType =
47	      entry.entryType === WorkEntryType.TIME
48	        ? LineItemType.TIMESHEET
49	        : LineItemType.PIECE_RATE;
50	
51	    const description =
52	      entry.entryType === WorkEntryType.TIME
53	        ? `Time entry: ${entry.durationMinutes} min on ${entry.date ? new Date(entry.date).toISOString().split('T')[0] : 'N/A'}`
54	        : `Piece rate: ${entry.quantity} x ${entry.itemDescription || 'items'}`;
55	
56	    const lineItem = await SettlementLineItem.create({
57	      settlementId: settlement._id,
58	      description,
59	      amountCents: entry.subtotalCents,
60	      type: lineItemType,
61	      workEntryId: entry._id,
62	      createdBy: generatedBy,
63	    });
64	    lineItems.push(lineItem);
65	  }
66	
67	  return { settlement, lineItems };
68	}
69	
70	/**
71	 * Add an adjustment to a settlement. Type and reason are required.
72	 */
73	export async function addAdjustment(
74	  settlementId: string,
75	  adjustmentType: AdjustmentType,
76	  amountCents: number,
77	  reason: string,
78	  createdBy: string
79	) {
80	  if (!reason || reason.trim().length === 0) {
81	    throw new ValidationError('Adjustment reason is required');
82	  }
83	
84	  const settlement = await Settlement.findById(settlementId);
85	  if (!settlement) {
86	    throw new NotFoundError('Settlement not found');
87	  }
88	
89	  if (settlement.status !== SettlementStatus.DRAFT && settlement.status !== SettlementStatus.PENDING_REVIEW) {
90	    throw new ValidationError(`Cannot add adjustments to a settlement with status: ${settlement.status}`);
91	  }
92	
93	  const description = `${adjustmentType}: ${reason}`;
94	
95	  const lineItem = await SettlementLineItem.create({
96	    settlementId,
97	    description,
98	    amountCents,
99	    type: LineItemType.ADJUSTMENT,
100	    adjustmentType,
101	    adjustmentReason: reason,
102	    createdBy,
103	  });
104	
105	  // Recalculate settlement totals
106	  settlement.adjustmentCents = addCents(settlement.adjustmentCents, amountCents);
107	  settlement.finalAmountCents = addCents(settlement.subtotalCents, settlement.adjustmentCents);
108	
109	  // Run variance check: threshold = max(subtotal * 0.02, 2500)
110	  const variance = varianceCheck(settlement.subtotalCents, settlement.finalAmountCents);
111	  settlement.variancePercent = variance.variancePercent;
112	  settlement.varianceAmountCents = variance.varianceAmountCents;
113	
114	  await settlement.save();
115	
116	  return { settlement, lineItem };
117	}
118	
119	/**
120	 * Finalize a settlement. Runs variance check and compliance hook.
121	 * Variance threshold = max(subtotal * 0.02, 2500).
122	 * If variance exceeds threshold, a varianceReason is required.
123	 */
124	export async function finalizeSettlement(
125	  settlementId: string,
126	  finalizedBy: string,
127	  varianceReason?: string
128	) {
129	  const settlement = await Settlement.findById(settlementId);
130	  if (!settlement) {
131	    throw new NotFoundError('Settlement not found');
132	  }
133	
134	  if (settlement.status !== SettlementStatus.DRAFT && settlement.status !== SettlementStatus.PENDING_REVIEW) {
135	    throw new ValidationError(`Cannot finalize a settlement with status: ${settlement.status}`);
136	  }
137	
138	  // Run variance check
139	  const variance = varianceCheck(settlement.subtotalCents, settlement.finalAmountCents);
140	
141	  if (variance.requiresReason) {
142	    if (!varianceReason || varianceReason.trim().length === 0) {
143	      throw new ValidationError(
144	        `Variance of ${variance.varianceAmountCents} cents exceeds threshold of ${variance.threshold} cents. A variance reason is required.`
145	      );
146	    }
147	    settlement.varianceReason = varianceReason;
148	  }
149	
150	  settlement.variancePercent = variance.variancePercent;
151	  settlement.varianceAmountCents = variance.varianceAmountCents;
152	
153	  // Run compliance hook
154	  const complianceResult = await beforeSettlementFinalize(settlement.toObject());
155	  if (!complianceResult.allow) {
156	    throw new ForbiddenError(
157	      complianceResult.reason || 'Compliance check failed for settlement finalization'
158	    );
159	  }
160	
161	  settlement.status = SettlementStatus.APPROVED;
162	  await settlement.save();
163	
164	  return settlement;
165	}
