167	export async function getSettlement(settlementId: string, requesterId?: string, requesterRole?: string) {
168	  const settlement = await Settlement.findById(settlementId);
169	  if (!settlement) {
170	    throw new NotFoundError('Settlement not found');
171	  }
172	
173	  // Object-level authorization: only participants or admins
174	  if (requesterId && requesterRole !== 'admin') {
175	    const isParticipant =
176	      settlement.clientId.toString() === requesterId ||
177	      settlement.photographerId.toString() === requesterId;
178	    if (!isParticipant) {
179	      throw new ForbiddenError('You do not have access to this settlement');
180	    }
181	  }
182	
183	  const lineItems = await SettlementLineItem.find({ settlementId }).sort({ createdAt: 1 }).lean();
184	
185	  return { settlement, lineItems };
186	}
