1	import { Payment, Settlement } from '../models';
2	import { SettlementStatus, PaymentMethod } from '../types/enums';
3	import { NotFoundError, ValidationError, ForbiddenError } from '../utils/errors';
4	
5	export interface RecordPaymentInput {
6	  settlementId: string;
7	  amountCents: number;
8	  method: PaymentMethod;
9	  receiptDetails: {
10	    referenceNumber?: string;
11	    date?: Date;
12	    notes?: string;
13	    attachmentId?: string;
14	  };
15	  recordedBy: string;
16	}
17	
18	export async function recordPayment(input: RecordPaymentInput) {
19	  const settlement = await Settlement.findById(input.settlementId);
20	  if (!settlement) {
21	    throw new NotFoundError('Settlement not found');
22	  }
23	
24	  if (settlement.status !== SettlementStatus.APPROVED) {
25	    throw new ValidationError(
26	      `Cannot record payment for a settlement with status: ${settlement.status}. Must be approved.`
27	    );
28	  }
29	
30	  if (input.amountCents <= 0) {
31	    throw new ValidationError('Payment amount must be positive');
32	  }
33	
34	  const payment = await Payment.create({
35	    settlementId: input.settlementId,
36	    amountCents: input.amountCents,
37	    method: input.method,
38	    receiptDetails: {
39	      referenceNumber: input.receiptDetails.referenceNumber,
40	      date: input.receiptDetails.date || new Date(),
41	      notes: input.receiptDetails.notes,
42	      attachmentId: input.receiptDetails.attachmentId,
43	    },
44	    paidAt: new Date(),
45	    recordedBy: input.recordedBy,
46	  });
47	
48	  // Check if total paid matches or exceeds settlement
49	  const allPayments = await Payment.find({ settlementId: input.settlementId }).lean();
50	  const totalPaid = allPayments.reduce((sum, p) => sum + p.amountCents, 0);
51	
52	  if (totalPaid >= settlement.finalAmountCents) {
53	    settlement.status = SettlementStatus.PAID;
54	    await settlement.save();
55	  }
56	
57	  return payment;
58	}
