60	export async function getPaymentsBySettlement(settlementId: string, requesterId?: string, requesterRole?: string) {
61	  if (requesterId && requesterRole !== 'admin') {
62	    const settlement = await Settlement.findById(settlementId);
63	    if (!settlement) throw new NotFoundError('Settlement not found');
64	    const isParticipant = settlement.clientId.toString() === requesterId || settlement.photographerId.toString() === requesterId;
65	    if (!isParticipant) throw new ForbiddenError('You do not have access to these payments');
66	  }
67	  return Payment.find({ settlementId }).sort({ paidAt: -1 }).lean();
