5	// Valid state transitions for the job status state machine
6	const JOB_STATUS_TRANSITIONS: Record<JobStatus, JobStatus[]> = {
7	  [JobStatus.DRAFT]: [JobStatus.POSTED, JobStatus.CANCELLED],
8	  [JobStatus.POSTED]: [JobStatus.ASSIGNED, JobStatus.CANCELLED],
9	  [JobStatus.ASSIGNED]: [JobStatus.IN_PROGRESS, JobStatus.CANCELLED],
10	  [JobStatus.IN_PROGRESS]: [JobStatus.REVIEW, JobStatus.DISPUTED, JobStatus.CANCELLED],
11	  [JobStatus.REVIEW]: [JobStatus.COMPLETED, JobStatus.IN_PROGRESS, JobStatus.DISPUTED],
12	  [JobStatus.COMPLETED]: [],
13	  [JobStatus.CANCELLED]: [],
14	  [JobStatus.DISPUTED]: [JobStatus.IN_PROGRESS, JobStatus.CANCELLED, JobStatus.COMPLETED],
15	};
