79	/**
80	 * Assign a photographer to a job.
81	 * The photographer must have verification status = VERIFIED.
82	 */
83	export async function assignPhotographer(
84	  jobId: string,
85	  photographerId: string,
86	  assignedBy: string,
87	  assignerRole: Role
88	) {
89	  const job = await Job.findById(jobId);
90	  if (!job) {
91	    throw new NotFoundError('Job not found');
92	  }
93	
94	  // Only the job client or an admin can assign
95	  if (job.clientId.toString() !== assignedBy && assignerRole !== Role.ADMIN) {
96	    throw new ForbiddenError('Only the job client or an admin can assign a photographer');
97	  }
98	
99	  if (job.status !== JobStatus.POSTED) {
100	    throw new ValidationError('Can only assign a photographer to a posted job');
101	  }
102	
103	  // Check photographer is verified
104	  const verification = await Verification.findOne({
105	    photographerId,
106	    status: VerificationStatus.VERIFIED,
107	  });
108	
109	  if (!verification) {
110	    throw new ValidationError(
111	      'Photographer must have verified status before being assigned to a job'
112	    );
113	  }
114	
115	  job.photographerId = photographerId as any;
116	  job.status = JobStatus.ASSIGNED;
117	  await job.save();
118	
119	  return job;
120	}
