122	/**
123	 * Transition job status following the state machine rules.
124	 */
125	export async function transitionStatus(
126	  jobId: string,
127	  newStatus: JobStatus,
128	  userId: string,
129	  userRole: Role
130	) {
131	  const job = await Job.findById(jobId);
132	  if (!job) {
133	    throw new NotFoundError('Job not found');
134	  }
135	
136	  // Check user is a participant or admin
137	  const isParticipant =
138	    job.clientId.toString() === userId ||
139	    (job.photographerId && job.photographerId.toString() === userId);
140	
141	  if (!isParticipant && userRole !== Role.ADMIN) {
142	    throw new ForbiddenError('You are not a participant in this job');
143	  }
144	
145	  const allowedTransitions = JOB_STATUS_TRANSITIONS[job.status as JobStatus];
146	  if (!allowedTransitions || !allowedTransitions.includes(newStatus)) {
147	    throw new ValidationError(
148	      `Cannot transition from ${job.status} to ${newStatus}`
149	    );
150	  }
151	
152	  job.status = newStatus;
153	
154	  if (newStatus === JobStatus.COMPLETED) {
155	    job.completedAt = new Date();
156	  }
157	
158	  await job.save();
159	  return job;
160	}
