162	/**
163	 * E-confirm service agreement. Both parties must type their password to confirm.
164	 * The agreement is displayed on-screen and confirmed by re-entering account password.
165	 * Both client and photographer must confirm before the job can proceed to IN_PROGRESS.
166	 */
167	export async function confirmAgreement(
168	  jobId: string,
169	  userId: string,
170	  password: string
171	): Promise<any> {
172	  const job = await Job.findById(jobId);
173	  if (!job) throw new NotFoundError('Job not found');
174	
175	  if (job.status !== JobStatus.ASSIGNED && job.status !== JobStatus.DRAFT && job.status !== JobStatus.POSTED) {
176	    throw new ValidationError('Agreement can only be confirmed on an assigned job');
177	  }
178	
179	  // Verify user is a participant
180	  const isClient = job.clientId.toString() === userId;
181	  const isPhotographer = job.photographerId && job.photographerId.toString() === userId;
182	  if (!isClient && !isPhotographer) {
183	    throw new ForbiddenError('Only job participants can confirm the agreement');
184	  }
185	
186	  // Re-authenticate: verify password against stored hash
187	  const user = await User.findById(userId);
188	  if (!user) throw new AuthError('User not found');
189	  const passwordValid = await user.comparePassword(password);
190	  if (!passwordValid) {
191	    throw new AuthError('Password verification failed. Agreement not confirmed.');
192	  }
193	
194	  // Find or create service agreement
195	  let agreement = await ServiceAgreement.findOne({ jobId });
196	  if (!agreement) {
197	    agreement = await ServiceAgreement.create({
198	      jobId,
199	      version: 1,
200	      content: `Service agreement for job "${job.title}". Agreed rate: ${job.agreedRateCents} cents per ${job.rateType === 'hourly' ? 'hour' : 'unit'}. Both parties agree to the terms of service.`,
201	    });
202	    job.serviceAgreementId = agreement._id as any;
203	  }
204	
205	  // Record confirmation
206	  if (isClient) {
207	    if (agreement.clientConfirmedAt) {
208	      throw new ValidationError('Client has already confirmed this agreement');
209	    }
210	    agreement.clientConfirmedAt = new Date();
211	    job.clientConfirmed = true;
212	  } else if (isPhotographer) {
213	    if (agreement.photographerConfirmedAt) {
214	      throw new ValidationError('Photographer has already confirmed this agreement');
215	    }
216	    agreement.photographerConfirmedAt = new Date();
217	    job.photographerConfirmed = true;
218	  }
219	
220	  await agreement.save();
221	
222	  // If both confirmed, transition to IN_PROGRESS
223	  if (agreement.clientConfirmedAt && agreement.photographerConfirmedAt) {
224	    job.status = JobStatus.IN_PROGRESS;
225	  }
226	
227	  await job.save();
228	
229	  return {
230	    job,
231	    agreement,
232	    clientConfirmed: !!agreement.clientConfirmedAt,
233	    photographerConfirmed: !!agreement.photographerConfirmedAt,
234	    fullyConfirmed: !!(agreement.clientConfirmedAt && agreement.photographerConfirmedAt),
235	  };
236	}
