238	export async function listJobs(filters: {
239	  clientId?: string;
240	  photographerId?: string;
241	  communityId?: string;
242	  status?: JobStatus;
243	  page?: number;
244	  limit?: number;
245	}) {
246	  const page = filters.page || 1;
247	  const limit = filters.limit || 20;
248	  const skip = (page - 1) * limit;
249	
250	  const query: any = {};
251	  if (filters.clientId) query.clientId = filters.clientId;
252	  if (filters.photographerId) query.photographerId = filters.photographerId;
253	  if (filters.communityId) query.communityId = filters.communityId;
254	  if (filters.status) query.status = filters.status;
255	
256	  const [jobs, total] = await Promise.all([
257	    Job.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit).lean(),
258	    Job.countDocuments(query),
259	  ]);
260	
261	  return { jobs, total, page, limit };
262	}
