17	  const [actionLoading, setActionLoading] = useState('');
18	
19	  const fetchData = async () => {
20	    setLoading(true);
21	    try {
22	      const [incRes, outRes] = await Promise.all([
23	        apiClient.get('/access-requests/incoming'),
24	        apiClient.get('/access-requests/outgoing'),
25	      ]);
26	      setIncoming(incRes.data.items || incRes.data || []);
27	      setOutgoing(outRes.data.items || outRes.data || []);
28	    } catch (err: any) {
29	      setError(err.response?.data?.msg || 'Failed to load access requests');
30	    } finally {
31	      setLoading(false);
32	    }
33	  };
34	
35	  useEffect(() => { fetchData(); }, []);
36	
