38	    setActionLoading(requestId);
39	    try {
40	      await apiClient.patch(`/access-requests/${requestId}/${action}`);
41	      await fetchData();
42	    } catch (err: any) {
43	      setError(err.response?.data?.msg || `Failed to ${action} request`);
44	    } finally {
45	      setActionLoading('');
46	    }
