66	      await fetchData();
67	    } catch (err: any) {
68	      setError(err.response?.data?.msg || 'Failed to create request');
69	    } finally {
70	      setSubmitting(false);
71	    }
72	  };
73	
74	  if (loading) return <LoadingSpinner message="Loading access requests..." />;
75	
76	  const items = tab === 'incoming' ? incoming : outgoing;
77	
78	  return (
79	    <div className="max-w-4xl mx-auto">
