16	  const [error, setError] = useState('');
17	  const [success, setSuccess] = useState('');
18	
19	  const handleSubmit = async (e: React.FormEvent) => {
20	    e.preventDefault();
21	    if (!id) return;
22	    setLoading(true);
23	    setError('');
24	    setSuccess('');
25	    try {
26	      await settlementsApi.recordPayment(id, {
27	        amountCents: Math.round(parseFloat(form.amountCents) * 100),
28	        paymentMethod: form.paymentMethod,
29	        reference: form.reference,
30	        notes: form.notes,
31	        paidAt: form.paidAt,
32	      });
33	      setSuccess('Payment recorded successfully.');
34	      setTimeout(() => navigate(`/settlements/${id}`), 1500);
35	    } catch (err: any) {
36	      setError(err.response?.data?.msg || 'Failed to record payment');
37	    } finally {
38	      setLoading(false);
39	    }
40	  };
41	
42	  return (
43	    <div className="max-w-xl mx-auto">
44	      <h1 className="text-2xl font-bold mb-6">Record Payment</h1>
45	      <p className="text-sm text-gray-500 mb-4">Settlement ID: <span className="font-mono">{id}</span></p>
46	      {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
47	      {success && <div className="bg-green-50 text-green-600 p-3 rounded mb-4 text-sm">{success}</div>}
48	      <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow p-6 space-y-5">
49	        <div>
50	          <label className="block text-sm font-medium text-gray-700 mb-1">Amount ($) *</label>
51	          <input type="number" step="0.01" min="0.01" value={form.amountCents} onChange={e => setForm({ ...form, amountCents: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" placeholder="0.00" />
52	        </div>
53	        <div>
54	          <label className="block text-sm font-medium text-gray-700 mb-1">Payment Method *</label>
55	          <select value={form.paymentMethod} onChange={e => setForm({ ...form, paymentMethod: e.target.value })} className="w-full border rounded px-3 py-2 text-sm">
56	            <option value="bank_transfer">Bank Transfer</option>
57	            <option value="check">Check</option>
58	            <option value="cash">Cash</option>
59	            <option value="paypal">PayPal</option>
60	            <option value="other">Other</option>
61	          </select>
62	        </div>
63	        <div>
64	          <label className="block text-sm font-medium text-gray-700 mb-1">Payment Date *</label>
65	          <input type="date" value={form.paidAt} onChange={e => setForm({ ...form, paidAt: e.target.value })} required className="w-full border rounded px-3 py-2 text-sm" />
66	        </div>
67	        <div>
68	          <label className="block text-sm font-medium text-gray-700 mb-1">Reference / Transaction ID</label>
69	          <input type="text" value={form.reference} onChange={e => setForm({ ...form, reference: e.target.value })} className="w-full border rounded px-3 py-2 text-sm" placeholder="Optional reference number" />
70	        </div>
71	        <div>
72	          <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
73	          <textarea value={form.notes} onChange={e => setForm({ ...form, notes: e.target.value })} rows={2} className="w-full border rounded px-3 py-2 text-sm" placeholder="Additional notes..." />
74	        </div>
75	        <div className="flex gap-3">
76	          <button type="submit" disabled={loading} className="bg-primary-600 text-white px-6 py-2 rounded hover:bg-primary-700 disabled:opacity-50 text-sm">
77	            {loading ? 'Recording...' : 'Record Payment'}
78	          </button>
79	          <button type="button" onClick={() => navigate(-1)} className="border px-6 py-2 rounded text-sm hover:bg-gray-50">Cancel</button>
80	        </div>
81	      </form>
82	    </div>
83	  );
84	}
