4	import LoadingSpinner from '../components/shared/LoadingSpinner';
5	import StatusBadge from '../components/shared/StatusBadge';
6	
7	const DATA_CATEGORIES = ['profile_data', 'portfolio_data', 'job_data', 'payment_data', 'analytics'];
8	
9	export default function ConsentManagementPage() {
10	  const [history, setHistory] = useState<any[]>([]);
11	  const [categories, setCategories] = useState<any[]>([]);
12	  const [currentPolicy, setCurrentPolicy] = useState<any>(null);
13	  const [loading, setLoading] = useState(true);
14	  const [error, setError] = useState('');
15	  const [actionLoading, setActionLoading] = useState('');
16	
17	  const fetchData = async () => {
18	    try {
19	      const [histRes, catRes, polRes] = await Promise.all([
20	        consentApi.getHistory(),
21	        consentApi.getCategoryConsents(),
22	        consentApi.getCurrentPolicy().catch(() => ({ data: null })),
23	      ]);
24	      setHistory(histRes.data.items || histRes.data || []);
25	      setCategories(catRes.data.items || catRes.data || []);
26	      setCurrentPolicy(polRes.data);
27	    } catch (err: any) {
28	      setError(err.response?.data?.msg || 'Failed to load consent data');
29	    } finally {
30	      setLoading(false);
31	    }
32	  };
33	
34	  useEffect(() => { fetchData(); }, []);
35	
36	  const handleGrantConsent = async (category: string) => {
37	    setActionLoading(category);
38	    try {
39	      await consentApi.recordCategoryConsent({ category });
40	      await fetchData();
41	    } catch (err: any) {
42	      setError(err.response?.data?.msg || 'Failed to grant consent');
43	    } finally {
44	      setActionLoading('');
45	    }
46	  };
47	
48	  const handleRevoke = async (category: string) => {
49	    if (!confirm(`Revoke consent for ${category.replace(/_/g, ' ')}?`)) return;
50	    setActionLoading(category);
51	    try {
52	      await consentApi.revokeCategoryConsent(category);
53	      await fetchData();
54	    } catch (err: any) {
55	      setError(err.response?.data?.msg || 'Failed to revoke consent');
56	    } finally {
57	      setActionLoading('');
58	    }
59	  };
60	
61	  const handleAcceptPolicy = async () => {
62	    if (!currentPolicy) return;
63	    setActionLoading('policy');
64	    try {
65	      await consentApi.recordConsent({ policyId: currentPolicy._id });
66	      await fetchData();
67	    } catch (err: any) {
68	      setError(err.response?.data?.msg || 'Failed to record consent');
69	    } finally {
70	      setActionLoading('');
71	    }
72	  };
73	
74	  if (loading) return <LoadingSpinner message="Loading consent data..." />;
75	
76	  const consentedCategories = new Set(categories.map((c: any) => c.category));
77	
78	  return (
79	    <div className="max-w-3xl mx-auto">
80	      <h1 className="text-2xl font-bold mb-6">Consent Management</h1>
81	      {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm">{error}</div>}
82	
83	      {currentPolicy && (
84	        <div className="bg-white rounded-lg shadow p-6 mb-6">
85	          <h2 className="font-semibold mb-2">Current Privacy Policy</h2>
86	          <p className="text-sm text-gray-600 mb-1">Version: {currentPolicy.version}</p>
87	          <p className="text-sm text-gray-600 mb-3">Effective: {formatDateTime(currentPolicy.effectiveDate || currentPolicy.createdAt)}</p>
88	          <button
89	            onClick={handleAcceptPolicy}
90	            disabled={actionLoading === 'policy'}
91	            className="bg-primary-600 text-white px-4 py-2 rounded text-sm hover:bg-primary-700 disabled:opacity-50"
92	          >
93	            {actionLoading === 'policy' ? 'Recording...' : 'Accept Current Policy'}
94	          </button>
95	        </div>
96	      )}
97	
98	      <div className="bg-white rounded-lg shadow mb-6">
99	        <div className="px-6 py-4 border-b">
100	          <h2 className="font-semibold">Data Categories</h2>
101	          <p className="text-xs text-gray-500 mt-1">Manage consent for each data processing category</p>
102	        </div>
103	        <div className="divide-y">
104	          {DATA_CATEGORIES.map(cat => {
105	            const isConsented = consentedCategories.has(cat);
106	            return (
107	              <div key={cat} className="flex items-center justify-between px-6 py-4">
108	                <div>
109	                  <span className="text-sm font-medium capitalize">{cat.replace(/_/g, ' ')}</span>
110	                  <span className="ml-2">
111	                    <StatusBadge status={isConsented ? 'active' : 'pending'} />
112	                  </span>
113	                </div>
114	                {isConsented ? (
115	                  <button
116	                    onClick={() => handleRevoke(cat)}
117	                    disabled={actionLoading === cat}
118	                    className="text-red-600 text-sm hover:underline disabled:opacity-50"
119	                  >
120	                    {actionLoading === cat ? 'Revoking...' : 'Revoke'}
121	                  </button>
122	                ) : (
123	                  <button
124	                    onClick={() => handleGrantConsent(cat)}
125	                    disabled={actionLoading === cat}
126	                    className="text-primary-600 text-sm hover:underline disabled:opacity-50"
127	                  >
128	                    {actionLoading === cat ? 'Granting...' : 'Grant Consent'}
129	                  </button>
130	                )}
131	              </div>
132	            );
133	          })}
134	        </div>
135	      </div>
136	
137	      <div className="bg-white rounded-lg shadow">
138	        <div className="px-6 py-4 border-b">
139	          <h2 className="font-semibold">Consent History</h2>
140	        </div>
141	        {history.length === 0 ? (
142	          <p className="p-6 text-sm text-gray-500">No consent history yet.</p>
143	        ) : (
144	          <table className="w-full text-sm">
145	            <thead><tr className="border-b bg-gray-50"><th className="text-left px-6 py-3">Action</th><th className="text-left px-6 py-3">Date</th><th className="text-left px-6 py-3">Details</th></tr></thead>
146	            <tbody>
147	              {history.map((h: any, i: number) => (
148	                <tr key={h._id || i} className="border-b">
149	                  <td className="px-6 py-3 capitalize">{h.action || h.type || 'consent'}</td>
150	                  <td className="px-6 py-3">{formatDateTime(h.createdAt || h.timestamp)}</td>
151	                  <td className="px-6 py-3 text-gray-600">{h.category || h.policyVersion || '-'}</td>
152	                </tr>
153	              ))}
154	            </tbody>
155	          </table>
156	        )}
157	      </div>
158	    </div>
159	  );
160	}
