1	import { Request, Response, NextFunction } from 'express';
2	import { ZodSchema, ZodError } from 'zod';
3	import { ValidationError } from '../utils/errors';
4	
5	export function validateRequest(schema: ZodSchema, source: 'body' | 'query' | 'params' = 'body') {
6	  return (req: Request, _res: Response, next: NextFunction): void => {
7	    try {
8	      const data = req[source];
9	      const parsed = schema.parse(data);
10	      (req as any)[source] = parsed;
11	      next();
12	    } catch (err) {
13	      if (err instanceof ZodError) {
14	        const message = err.errors.map(e => `${e.path.join('.')}: ${e.message}`).join(', ');
15	        return next(new ValidationError(message));
16	      }
17	      next(err);
18	    }
19	  };
20	}
