1	import express from 'express';
2	import helmet from 'helmet';
3	import cors from 'cors';
4	import { requestId } from './middleware/requestId';
5	import { rateLimiter } from './middleware/rateLimiter';
6	import { nonceReplay } from './middleware/nonceReplay';
7	import { auditLogger } from './middleware/auditLogger';
8	import { authenticate } from './middleware/authenticate';
9	import { blacklistCheck } from './middleware/blacklistCheck';
10	import { deviceFingerprintMiddleware } from './middleware/deviceFingerprint';
11	import { errorHandler } from './middleware/errorHandler';
12	import { mountRoutes } from './routes';
13	
14	const app = express();
15	
16	// 1. Security headers
17	app.use(helmet({
18	  contentSecurityPolicy: {
19	    directives: {
20	      defaultSrc: ["'self'"],
21	      scriptSrc: ["'self'"],
22	      styleSrc: ["'self'", "'unsafe-inline'"],
23	      imgSrc: ["'self'", "data:"],
24	    },
25	  },
26	  hsts: { maxAge: 31536000, includeSubDomains: true },
27	}));
28	
29	// 2. CORS
30	app.use(cors({
31	  origin: true,
32	  credentials: true,
33	  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
34	  allowedHeaders: ['Content-Type', 'Authorization', 'X-Nonce', 'X-Timestamp', 'X-Device-Fingerprint', 'X-Request-Id'],
35	}));
36	
37	// 3. Body parsing
38	app.use(express.json({ limit: '10mb' }));
39	app.use(express.urlencoded({ extended: true, limit: '10mb' }));
40	
41	// 4. Request ID
42	app.use(requestId);
43	
44	// 5. Rate limiting (before auth to catch brute force)
45	app.use(rateLimiter);
46	
47	// 6. Nonce replay protection
48	app.use(nonceReplay);
49	
50	// 7. Audit logger (pre)
51	app.use(auditLogger);
52	
53	// 8. Authentication
54	app.use(authenticate);
55	
56	// 9. Blacklist check
57	app.use(blacklistCheck);
58	
59	// 10. Device fingerprint (consent-gated)
60	app.use(deviceFingerprintMiddleware);
61	
62	// 11. Routes
63	mountRoutes(app);
64	
65	// 12. Error handler (must be last)
66	app.use(errorHandler);
67	
68	export default app;
