1	import { Request, Response, NextFunction } from 'express';
2	import { config } from '../config';
3	import { RateLimitError } from '../utils/errors';
4	
5	interface RateLimitEntry {
6	  count: number;
7	  resetAt: number;
8	}
9	
10	const windowMs = 60_000;
11	const limits = new Map<string, RateLimitEntry>();
12	
13	setInterval(() => {
14	  const now = Date.now();
15	  for (const [key, entry] of limits) {
16	    if (entry.resetAt <= now) limits.delete(key);
17	  }
18	}, 30_000);
19	
20	export function rateLimiter(req: Request, _res: Response, next: NextFunction): void {
21	  const key = req.user?.userId || req.ip || 'unknown';
22	  const now = Date.now();
23	  let entry = limits.get(key);
24	
25	  if (!entry || entry.resetAt <= now) {
26	    entry = { count: 0, resetAt: now + windowMs };
27	    limits.set(key, entry);
28	  }
29	
30	  entry.count++;
31	
32	  if (entry.count > config.rateLimitPerMin) {
33	    return next(new RateLimitError('Rate limit exceeded. Maximum 60 requests per minute.'));
34	  }
35	
36	  next();
37	}
