51	      title: req.body.title,
52	      description: req.body.description,
53	      clientId: req.user!.userId,
54	      communityId: req.user!.communityId,
55	      jobType: req.body.jobType,
56	      rateType: req.body.rateType,
57	      agreedRateCents: req.body.agreedRateCents || req.body.rate,
58	      estimatedTotalCents: req.body.estimatedTotalCents,
59	    });
60	    res.status(201).json(job);
61	  } catch (err) {
62	    next(err);
63	  }
