111	export async function confirmAgreement(req: Request, res: Response, next: NextFunction): Promise<void> {
112	  try {
113	    const { password } = req.body;
114	    if (!password) {
115	      res.status(400).json({ code: 400, msg: 'Password is required to confirm agreement' });
