1	const http = require('http');
2	const crypto = require('crypto');
3	
4	const BASE = process.env.API_BASE || 'http://server:3001';
5	
6	function request(method, path, body, token) {
7	  return new Promise((resolve, reject) => {
8	    const url = new URL(path, BASE);
9	    const nonce = crypto.randomUUID();
10	    const timestamp = Date.now().toString();
11	    const options = {
12	      hostname: url.hostname,
13	      port: url.port,
14	      path: url.pathname,
15	      method,
16	      headers: {
17	        'Content-Type': 'application/json',
18	        'X-Nonce': nonce,
19	        'X-Timestamp': timestamp,
20	      },
21	    };
22	    if (token) options.headers['Authorization'] = `Bearer ${token}`;
23	    const req = http.request(options, (res) => {
24	      let data = '';
25	      res.on('data', chunk => data += chunk);
26	      res.on('end', () => {
27	        try { resolve({ status: res.statusCode, data: JSON.parse(data) }); }
28	        catch { resolve({ status: res.statusCode, data }); }
29	      });
30	    });
31	    req.on('error', reject);
32	    if (body) req.write(JSON.stringify(body));
33	    req.end();
34	  });
35	}
36	
37	module.exports = { request, BASE };
