139	      ipAddress: input.ipAddress,
140	      outcome: 'failure',
141	    });
142	    throw new AuthError('Invalid email or password');
143	  }
144	
145	  // Successful login — reset failed attempts
146	  user.failedLoginAttempts = 0;
147	  user.lastLoginAt = new Date();
148	  user.lastActivityAt = new Date();
149	  await user.save();
150	
151	  const { token, jti, expiresAt } = issueToken(user._id.toString(), user.role);
152	
153	  const session = await Session.create({
154	    userId: user._id,
155	    jti,
156	    deviceFingerprint: input.deviceFingerprint,
157	    issuedAt: new Date(),
158	    lastActivityAt: new Date(),
159	    absoluteExpiry: expiresAt,
160	  });
161	
162	  await logEvent({
163	    actorId: user._id.toString(),
164	    actorRole: user.role,
165	    action: AUDIT_EVENTS.LOGIN_SUCCESS,
166	    resource: 'auth',
167	    resourceId: user._id.toString(),
168	    ipAddress: input.ipAddress,
169	    deviceFingerprint: input.deviceFingerprint,
170	    outcome: 'success',
171	  });
172	
173	  return { user, token, session };
174	}
175	
176	export async function logout(jti: string, userId: string): Promise<void> {
177	  const session = await Session.findOne({ jti, isRevoked: false });
178	  if (!session) {
179	    return; // Already revoked or doesn't exist — idempotent
180	  }
181	
182	  // Verify the session belongs to the requesting user
183	  if (session.userId.toString() !== userId) {
184	    throw new ForbiddenError('Cannot revoke another user\'s session');
185	  }
186	
187	  session.isRevoked = true;
188	  session.revokedAt = new Date();
189	  await session.save();
190	}
