7	export interface CreateWorkEntryInput {
8	  jobId: string;
9	  photographerId: string;
10	  entryType: WorkEntryType;
11	  date?: Date;
12	  startTime?: string;
13	  endTime?: string;
14	  durationMinutes?: number;
15	  itemDescription?: string;
16	  quantity?: number;
17	  unitRateCents?: number;
18	  notes?: string;
