21	/**
22	 * Create a work entry. For TIME entries, validate 15-minute alignment.
23	 */
24	export async function createWorkEntry(input: CreateWorkEntryInput) {
25	  const job = await Job.findById(input.jobId);
26	  if (!job) {
27	    throw new NotFoundError('Job not found');
28	  }
29	
30	  if (
31	    job.status !== JobStatus.IN_PROGRESS &&
32	    job.status !== JobStatus.REVIEW
33	  ) {
34	    throw new ValidationError('Work entries can only be added to in-progress or review jobs');
35	  }
36	
37	  if (job.photographerId?.toString() !== input.photographerId) {
38	    throw new ForbiddenError('Only the assigned photographer can create work entries');
39	  }
40	
41	  let subtotalCents: number;
42	
43	  if (input.entryType === WorkEntryType.TIME) {
44	    if (!input.durationMinutes || input.durationMinutes <= 0) {
45	      throw new ValidationError('Duration in minutes is required for time entries');
46	    }
47	
48	    // Validate 15-minute alignment
49	    if (input.durationMinutes % TIMESHEET_INCREMENT_MINUTES !== 0) {
50	      throw new ValidationError(
51	        `Duration must be in ${TIMESHEET_INCREMENT_MINUTES}-minute increments`
52	      );
53	    }
54	
55	    subtotalCents = calculateTimeEntryCents(job.agreedRateCents, input.durationMinutes);
56	  } else {
57	    // PIECE_RATE
58	    if (!input.quantity || input.quantity <= 0) {
59	      throw new ValidationError('Quantity is required for piece rate entries');
60	    }
61	
62	    const unitRate = input.unitRateCents ?? job.agreedRateCents;
63	    subtotalCents = calculatePieceRateCents(unitRate, input.quantity);
64	  }
65	
66	  const entry = await WorkEntry.create({
67	    jobId: input.jobId,
68	    photographerId: input.photographerId,
69	    entryType: input.entryType,
70	    date: input.date || new Date(),
71	    startTime: input.startTime,
72	    endTime: input.endTime,
73	    durationMinutes: input.durationMinutes,
74	    itemDescription: input.itemDescription,
75	    quantity: input.quantity,
76	    unitRateCents: input.unitRateCents,
77	    subtotalCents,
78	    notes: input.notes,
79	    isLocked: false,
80	  });
81	
82	  return entry;
83	}
