5	
6	export interface SendMessageInput {
7	  jobId: string;
8	  senderId: string;
9	  messageText: string;
10	}
11	
12	/**
13	 * Send a message on a job. Runs content filter — if flagged words found,
14	 * message is created with PENDING review status.
15	 */
16	export async function sendMessage(input: SendMessageInput) {
17	  const job = await Job.findById(input.jobId);
18	  if (!job) {
19	    throw new NotFoundError('Job not found');
20	  }
21	
22	  // Verify sender is a participant
23	  const isParticipant =
24	    job.clientId.toString() === input.senderId ||
25	    (job.photographerId && job.photographerId.toString() === input.senderId);
26	
27	  if (!isParticipant) {
28	    throw new ForbiddenError('Only job participants can send messages');
29	  }
30	
31	  // Run content filter
32	  const filterResult = scanText(input.messageText);
33	  const reviewStatus = filterResult.isClean
34	    ? ContentReviewStatus.APPROVED
35	    : ContentReviewStatus.PENDING;
36	
37	  const message = await JobMessage.create({
38	    jobId: input.jobId,
39	    senderId: input.senderId,
40	    messageText: input.messageText,
41	    reviewStatus,
42	    flaggedWords: filterResult.matchedWords,
43	  });
44	
45	  return message;
46	}
