48	/**
49	 * List messages for a job.
50	 * Messages with PENDING review status are only visible to the sender.
51	 */
52	export async function listMessages(
53	  jobId: string,
54	  viewerId: string,
55	  viewerRole: Role,
56	  page = 1,
57	  limit = 50
58	) {
59	  const job = await Job.findById(jobId);
60	  if (!job) {
61	    throw new NotFoundError('Job not found');
62	  }
63	
64	  // Verify viewer is a participant or admin
65	  const isParticipant =
66	    job.clientId.toString() === viewerId ||
67	    (job.photographerId && job.photographerId.toString() === viewerId);
68	
69	  if (!isParticipant && viewerRole !== Role.ADMIN) {
70	    throw new ForbiddenError('Only job participants can view messages');
71	  }
72	
73	  const skip = (page - 1) * limit;
74	
75	  // Fetch all messages for the job
76	  const messages = await JobMessage.find({ jobId })
77	    .sort({ createdAt: 1 })
78	    .skip(skip)
79	    .limit(limit)
80	    .lean();
81	
82	  // Filter: pending messages are only visible to their sender (or admin)
83	  const filtered = messages.filter(msg => {
84	    if (msg.reviewStatus === ContentReviewStatus.PENDING) {
85	      return msg.senderId.toString() === viewerId || viewerRole === Role.ADMIN;
86	    }
87	    return msg.reviewStatus === ContentReviewStatus.APPROVED || viewerRole === Role.ADMIN;
88	  });
89	
90	  const total = await JobMessage.countDocuments({ jobId });
91	
92	  return { messages: filtered, total, page, limit };
93	}
