17	  }
18	  const report = await Report.create({
19	    ...data,
20	    reporterId,
21	    status: ReportStatus.SUBMITTED,
22	    statusHistory: [{ status: ReportStatus.SUBMITTED, changedBy: reporterId, changedAt: new Date() }],
23	  });
24	  await AuditLog.create({
25	    timestamp: new Date(), actorId: reporterId, action: AUDIT_EVENTS.REPORT_CREATED,
26	    resource: 'report', resourceId: report._id!.toString(), outcome: 'success',
