44	export async function reviewReport(id: string, adminId: string, status: ReportStatus, notes?: string, resolution?: string) {
45	  const report = await Report.findById(id);
46	  if (!report) throw new NotFoundError('Report not found');
47	
48	  const validTransitions: Record<string, string[]> = {
49	    [ReportStatus.SUBMITTED]: [ReportStatus.UNDER_REVIEW],
50	    [ReportStatus.UNDER_REVIEW]: [ReportStatus.NEEDS_MORE_INFO, ReportStatus.ACTION_TAKEN, ReportStatus.REJECTED],
51	    [ReportStatus.NEEDS_MORE_INFO]: [ReportStatus.UNDER_REVIEW, ReportStatus.CLOSED],
52	    [ReportStatus.ACTION_TAKEN]: [ReportStatus.CLOSED],
53	    [ReportStatus.REJECTED]: [ReportStatus.CLOSED],
54	  };
55	  if (!validTransitions[report.status]?.includes(status)) {
56	    throw new ValidationError(`Cannot transition from ${report.status} to ${status}`);
57	  }
58	
59	  report.status = status;
60	  report.statusHistory.push({ status, changedBy: adminId as any, changedAt: new Date(), notes });
61	  if (resolution) report.resolution = resolution;
62	  report.reviewedBy = adminId as any;
63	  report.reviewedAt = new Date();
64	  return report.save();
65	}
