84	 * Get a profile with privacy rules applied based on the viewer's identity.
85	 */
86	export async function getProfileWithPrivacy(
87	  targetUserId: string,
88	  viewer: ProfileViewer
89	) {
90	  const profile = await Profile.findOne({ userId: targetUserId });
91	  if (!profile) {
92	    throw new NotFoundError('Profile not found');
93	  }
94	
95	  const targetUser = await User.findById(targetUserId);
96	  if (!targetUser) {
97	    throw new NotFoundError('User not found');
98	  }
99	
100	  // Owner or admin sees everything
101	  if (viewer.userId === targetUserId || viewer.role === Role.ADMIN) {
102	    return profile.toObject();
103	  }
104	
105	  const profileObj = profile.toObject() as any;
106	  const privacySettings = profileObj.privacySettings || {};
107	
108	  const privacyFields: string[] = [
109	    'firstName', 'lastName', 'phone', 'email', 'bio',
110	    'location', 'employer', 'graduationYear',
111	  ];
112	
113	  for (const field of privacyFields) {
114	    const level = (privacySettings as any)[field] as PrivacyLevel;
115	    const rawValue = (profileObj as any)[field];
116	
117	    if (rawValue === undefined || rawValue === null || rawValue === '') {
118	      continue;
119	    }
120	
121	    (profileObj as any)[field] = applyFieldPrivacy(
122	      field,
123	      String(rawValue),
124	      level,
125	      viewer.isAlumni,
126	      viewer.communityId,
127	      targetUser.communityId
128	    );
129	  }
130	
131	  return profileObj;
132	}
