    const userIds = communityUsers.map(u => u._id);
    query.userId = { $in: userIds };
  }

  const [profiles, total] = await Promise.all([
    Profile.find(query).sort({ createdAt: -1 }).skip(skip).limit(limit).lean(),
    Profile.countDocuments(query),
  ]);

