  const minimized = profiles.map(p => ({
    _id: p._id,
    userId: p.userId,
    firstName: p.firstName,
    lastName: p.lastName,
    displayName: (p as any).displayName,
    createdAt: (p as any).createdAt,
  }));

  return { profiles: minimized, total, page, limit };
}"}

