1	import { Job, FileAttachment } from '../models';
2	import { Role } from '../types/enums';
3	import { NotFoundError, ForbiddenError } from '../utils/errors';
4	import { logEvent } from './audit.service';
5	import { AUDIT_EVENTS } from '../utils/constants';
6	
7	/**
8	 * Authorization matrix for document access:
9	 * - Admin: full access
10	 * - Job client: access to documents related to their jobs
11	 * - Job photographer: access to documents related to their jobs
12	 * - All others: denied + audit-logged
13	 */
14	export async function checkDocumentAccess(
15	  fileId: string,
16	  userId: string,
17	  userRole: Role,
18	  ipAddress?: string
19	): Promise<{ allowed: boolean; file: any }> {
20	  const file = await FileAttachment.findById(fileId);
21	  if (!file) {
22	    throw new NotFoundError('Document not found');
23	  }
24	
25	  // Admins always have access
26	  if (userRole === Role.ADMIN) {
27	    return { allowed: true, file: file.toObject() };
28	  }
29	
30	  // Check if the user is a participant in the parent job
31	  if (file.parentType === 'settlement' || file.parentType === 'verification' || file.parentType === 'portfolio') {
