8	export function startScheduler(): void {
9	  // Every hour: expire access requests
10	  cron.schedule('0 * * * *', async () => {
11	    try {
12	      await expireAccessRequests();
13	    } catch (err) {
14	      logger.error('Access request expiry job failed', { error: err });
15	    }
16	  });
17	
18	  // Every hour: lock fully confirmed work entries after 48h
19	  cron.schedule('30 * * * *', async () => {
20	    try {
21	      await lockWorkEntries();
22	    } catch (err) {
23	      logger.error('Work entry locking job failed', { error: err });
24	    }
25	  });
26	
27	  // Every 10 minutes: cleanup nonces (safety net for TTL)
28	  cron.schedule('*/10 * * * *', async () => {
29	    try {
30	      await cleanupNonces();
31	    } catch (err) {
32	      logger.error('Nonce cleanup job failed', { error: err });
33	    }
34	  });
35	
36	  // Daily at midnight: check consent re-requirements
37	  cron.schedule('0 0 * * *', async () => {
38	    try {
39	      await recheckConsents();
40	    } catch (err) {
41	      logger.error('Consent recheck job failed', { error: err });
