1	import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
2	import apiClient from '../api/client';
3	import { User } from '../types';
4	
5	interface AuthContextType {
6	  user: User | null;
7	  token: string | null;
8	  isAuthenticated: boolean;
9	  login: (username: string, password: string) => Promise<void>;
10	  register: (data: { username: string; email: string; password: string; role?: string }) => Promise<void>;
11	  logout: () => Promise<void>;
12	}
13	
14	const AuthContext = createContext<AuthContextType | undefined>(undefined);
15	
16	export function AuthProvider({ children }: { children: ReactNode }) {
17	  const [user, setUser] = useState<User | null>(() => {
18	    const stored = localStorage.getItem('user');
19	    return stored ? JSON.parse(stored) : null;
20	  });
21	  const [token, setToken] = useState<string | null>(() => localStorage.getItem('token'));
22	
23	  const isAuthenticated = !!token && !!user;
24	
25	  async function login(username: string, password: string) {
26	    const res = await apiClient.post('/auth/login', { username, password });
27	    const { token: newToken, user: newUser } = res.data;
28	    localStorage.setItem('token', newToken);
29	    localStorage.setItem('user', JSON.stringify(newUser));
30	    setToken(newToken);
31	    setUser(newUser);
32	  }
33	
34	  async function register(data: { username: string; email: string; password: string; role?: string }) {
35	    const res = await apiClient.post('/auth/register', data);
36	    const { token: newToken, user: newUser } = res.data;
37	    localStorage.setItem('token', newToken);
38	    localStorage.setItem('user', JSON.stringify(newUser));
39	    setToken(newToken);
40	    setUser(newUser);
41	  }
42	
43	  async function logout() {
44	    try {
45	      await apiClient.post('/auth/logout');
46	    } catch {}
47	    localStorage.removeItem('token');
48	    localStorage.removeItem('user');
49	    setToken(null);
50	    setUser(null);
51	  }
52	
53	  return (
54	    <AuthContext.Provider value={{ user, token, isAuthenticated, login, register, logout }}>
55	      {children}
56	    </AuthContext.Provider>
57	  );
58	}
59	
60	export function useAuth() {
61	  const ctx = useContext(AuthContext);
62	  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
63	  return ctx;
64	}
