1	import { Deliverable, Job, User } from '../models';
2	import { ValidationError, NotFoundError, ForbiddenError } from '../utils/errors';
3	
4	export async function upload(jobId: string, photographerId: string, filePath: string, copyrightNotice: string, uploadedBy: string) {
5	  if (!copyrightNotice) throw new ValidationError('Copyright notice is required');
6	  return Deliverable.create({ jobId, photographerId, filePath, copyrightNotice, uploadedBy, visibleTo: [uploadedBy] });
7	}
8	
9	export async function getByJob(jobId: string, requesterId: string) {
10	  const job = await Job.findById(jobId);
11	  if (!job) throw new NotFoundError('Job not found');
12	
13	  const requester = await User.findById(requesterId);
14	  if (requester?.role !== 'admin') {
15	    const isParticipant =
16	      job.clientId.toString() === requesterId ||
17	      (job.photographerId && job.photographerId.toString() === requesterId);
18	    if (!isParticipant) {
19	      throw new ForbiddenError('Only job participants can view deliverables');
20	    }
21	  }
22	
23	  return Deliverable.find({ jobId }).sort({ createdAt: -1 });
24	}
