1	import { Request, Response, NextFunction } from 'express';
2	import { z } from 'zod';
3	import * as deliverableService from '../services/deliverable.service';
4	import * as fileService from '../services/file.service';
5	
6	export const jobIdParamSchema = z.object({
7	  jobId: z.string().min(1),
8	});
9	
10	export async function upload(req: Request, res: Response, next: NextFunction): Promise<void> {
11	  try {
12	    if (!req.file) {
13	      res.status(400).json({ code: 400, msg: 'No file uploaded' });
14	      return;
15	    }
16	    const { storagePath } = await fileService.saveFile({
17	      buffer: req.file.buffer,
18	      originalName: req.file.originalname,
19	      mimeType: req.file.mimetype,
20	      parentType: 'deliverable',
21	      parentId: req.params.jobId,
22	      uploadedBy: req.user!.userId,
23	    });
24	    const deliverable = await deliverableService.upload(
25	      req.params.jobId,
26	      req.user!.userId,
27	      storagePath,
28	      req.body.copyrightNotice || '',
29	      req.user!.userId,
30	    );
31	    res.status(201).json(deliverable);
32	  } catch (err) {
33	    next(err);
34	  }
35	}
36	
37	export async function getByJob(req: Request, res: Response, next: NextFunction): Promise<void> {
38	  try {
39	    const deliverables = await deliverableService.getByJob(req.params.jobId, req.user!.userId);
40	    res.status(200).json(deliverables);
41	  } catch (err) {
42	    next(err);
43	  }
44	}
