1	import { Consent, PrivacyPolicy } from '../models';
2	import { NotFoundError, ValidationError } from '../utils/errors';
3	import { CONSENT_RECHECK_DAYS } from '../utils/constants';
4	import { logEvent } from './audit.service';
5	import { AUDIT_EVENTS } from '../utils/constants';
6	
7	export interface RecordConsentInput {
8	  userId: string;
9	  policyVersion: string;
10	  purposes: { purpose: string; consented: boolean }[];
11	}
12	
13	export async function recordConsent(input: RecordConsentInput) {
14	  const policy = await PrivacyPolicy.findOne({ version: input.policyVersion });
15	  if (!policy) {
16	    throw new NotFoundError(`Privacy policy version ${input.policyVersion} not found`);
17	  }
18	
19	  // Deactivate any previous active consent for this user
20	  await Consent.updateMany(
21	    { userId: input.userId, isActive: true },
22	    { $set: { isActive: false } }
23	  );
24	
25	  const now = new Date();
26	  const reconsentDeadline = new Date(now.getTime() + CONSENT_RECHECK_DAYS * 24 * 60 * 60 * 1000);
27	
28	  const consent = await Consent.create({
29	    userId: input.userId,
30	    policyVersion: input.policyVersion,
31	    purposes: input.purposes.map(p => ({
32	      purpose: p.purpose,
33	      consented: p.consented,
34	      consentedAt: now,
35	    })),
36	    consentedAt: now,
37	    reconsentDeadline,
38	    isActive: true,
39	  });
40	
41	  await logEvent({
42	    actorId: input.userId,
43	    action: AUDIT_EVENTS.CONSENT_GRANTED,
44	    resource: 'consent',
45	    resourceId: consent._id.toString(),
46	    details: { policyVersion: input.policyVersion, purposes: input.purposes },
47	    outcome: 'success',
48	  });
49	
50	  return consent;
51	}
52	
53	export async function checkConsentCurrent(userId: string): Promise<{
54	  isCurrent: boolean;
55	  consent: any | null;
56	  needsReconsent: boolean;
57	}> {
58	  const activeConsent = await Consent.findOne({ userId, isActive: true });
59	
60	  if (!activeConsent) {
61	    return { isCurrent: false, consent: null, needsReconsent: true };
62	  }
63	
64	  const latestPolicy = await PrivacyPolicy.findOne().sort({ effectiveDate: -1 });
65	
66	  if (!latestPolicy) {
67	    return { isCurrent: true, consent: activeConsent, needsReconsent: false };
68	  }
69	
70	  // Consent is stale if policy version doesn't match the latest
71	  if (activeConsent.policyVersion !== latestPolicy.version) {
72	    return { isCurrent: false, consent: activeConsent, needsReconsent: true };
73	  }
74	
75	  // Check reconsent deadline
76	  const now = new Date();
77	  if (activeConsent.reconsentDeadline && now > activeConsent.reconsentDeadline) {
78	    return { isCurrent: false, consent: activeConsent, needsReconsent: true };
79	  }
80	
81	  return { isCurrent: true, consent: activeConsent, needsReconsent: false };
82	}
83	
84	export async function getPolicyHistory() {
85	  return PrivacyPolicy.find().sort({ effectiveDate: -1 }).lean();
86	}
87	
88	export async function getConsentHistory(userId: string) {
89	  const history = await Consent.find({ userId })
90	    .sort({ consentedAt: -1 })
91	    .lean();
92	  return history;
93	}
