1	import { DataCategoryConsent } from '../models';
2	import { NotFoundError, ValidationError } from '../utils/errors';
3	import { DATA_CATEGORIES, AUDIT_EVENTS } from '../utils/constants';
4	import { logEvent } from './audit.service';
5	
6	export async function checkConsent(
7	  userId: string,
8	  dataCategory: string
9	): Promise<{ hasConsent: boolean; consent: any | null }> {
10	  const consent = await DataCategoryConsent.findOne({
11	    userId,
12	    dataCategory,
13	    revokedAt: { $exists: false },
14	  });
15	
16	  return {
17	    hasConsent: !!consent,
18	    consent: consent ? consent.toObject() : null,
19	  };
20	}
21	
22	export interface RecordDataCategoryConsentInput {
23	  userId: string;
24	  dataCategory: string;
25	  disclosureText: string;
26	  purposeDescription: string;
27	}
28	
29	export async function recordConsent(input: RecordDataCategoryConsentInput) {
30	  if (!DATA_CATEGORIES.includes(input.dataCategory as any)) {
31	    throw new ValidationError(
32	      `Invalid data category: ${input.dataCategory}. Must be one of: ${DATA_CATEGORIES.join(', ')}`
33	    );
34	  }
35	
36	  // Revoke any existing active consent for this category before recording new one
37	  await DataCategoryConsent.updateMany(
38	    { userId: input.userId, dataCategory: input.dataCategory, revokedAt: { $exists: false } },
39	    { $set: { revokedAt: new Date() } }
40	  );
41	
42	  const consent = await DataCategoryConsent.create({
43	    userId: input.userId,
44	    dataCategory: input.dataCategory,
45	    disclosureText: input.disclosureText,
46	    purposeDescription: input.purposeDescription,
47	    consentedAt: new Date(),
48	  });
49	
50	  await logEvent({
