53	export async function checkConsentCurrent(userId: string): Promise<{
54	  isCurrent: boolean;
55	  consent: any | null;
56	  needsReconsent: boolean;
57	}> {
58	  const activeConsent = await Consent.findOne({ userId, isActive: true });
59	
60	  if (!activeConsent) {
61	    return { isCurrent: false, consent: null, needsReconsent: true };
62	  }
63	
64	  const latestPolicy = await PrivacyPolicy.findOne().sort({ effectiveDate: -1 });
65	
66	  if (!latestPolicy) {
67	    return { isCurrent: true, consent: activeConsent, needsReconsent: false };
68	  }
69	
70	  // Consent is stale if policy version doesn't match the latest
71	  if (activeConsent.policyVersion !== latestPolicy.version) {
72	    return { isCurrent: false, consent: activeConsent, needsReconsent: true };
73	  }
74	
75	  // Check reconsent deadline
76	  const now = new Date();
77	  if (activeConsent.reconsentDeadline && now > activeConsent.reconsentDeadline) {
78	    return { isCurrent: false, consent: activeConsent, needsReconsent: true };
79	  }
80	
81	  return { isCurrent: true, consent: activeConsent, needsReconsent: false };
82	}
