14	  const [loading, setLoading] = useState(true);
15	  const [error, setError] = useState('');
16	  const [showForm, setShowForm] = useState(false);
17	  const [form, setForm] = useState({ amountCents: '', description: '' });
18	  const [saving, setSaving] = useState(false);
19	
20	  const fetchData = async () => {
21	    if (!jobId) return;
22	    try {
23	      const [jobRes, escrowRes] = await Promise.all([
24	        jobsApi.getById(jobId),
25	        jobsApi.getEscrow(jobId),
26	      ]);
27	      setJob(jobRes.data);
28	      setEscrow(escrowRes.data);
29	    } catch (err: any) {
30	      setError(err.response?.data?.msg || 'Failed to load escrow data');
31	    } finally {
32	      setLoading(false);
33	    }
34	  };
35	
36	  useEffect(() => { fetchData(); }, [jobId]);
37	
38	  const handleAddEscrow = async (e: React.FormEvent) => {
39	    e.preventDefault();
40	    if (!jobId) return;
41	    setSaving(true);
42	    setError('');
43	    try {
44	      await jobsApi.addEscrow(jobId, {
45	        amountCents: Math.round(parseFloat(form.amountCents) * 100),
