80	        <div className="text-center">
81	          <p className="text-sm text-gray-500">Current Balance</p>
82	          <p className="text-3xl font-bold mt-1"><MoneyDisplay cents={balance} /></p>
83	        </div>
84	      </div>
85	
86	      {showForm && (
87	        <form onSubmit={handleAddEscrow} className="bg-white rounded-lg shadow p-6 mb-6 space-y-4">
