1	import { Verification, User } from '../models';
2	import { VerificationStatus, Role } from '../types/enums';
3	import { NotFoundError, ValidationError, ForbiddenError } from '../utils/errors';
4	import { encrypt, decrypt } from './encryption.service';
5	import { maskIdentifier } from '../utils/masking';
6	import { logEvent } from './audit.service';
7	import { AUDIT_EVENTS } from '../utils/constants';
8	import { beforeVerificationApprove } from '../hooks/complianceHooks';
9	
10	export interface SubmitVerificationInput {
11	  photographerId: string;
12	  realName: string;
13	  qualificationType: string;
14	  issuingAuthority?: string;
15	  idDocumentPath: string;
16	  qualificationDocPaths: string[];
17	  fileChecksums: string[];
18	}
19	
20	export async function submitVerification(input: SubmitVerificationInput) {
21	  // Encrypt sensitive fields
22	  const encryptedRealName = encrypt(input.realName, 'government_id');
23	  const encryptedIdDocPath = encrypt(input.idDocumentPath, 'government_id');
24	  const encryptedQualDocPaths = input.qualificationDocPaths.map(
25	    p => encrypt(p, 'qualification_documents')
26	  );
27	
28	  const verification = await Verification.create({
29	    photographerId: input.photographerId,
30	    realName: encryptedRealName,
31	    qualificationType: input.qualificationType,
32	    issuingAuthority: input.issuingAuthority,
33	    idDocumentPath: encryptedIdDocPath,
34	    qualificationDocPaths: encryptedQualDocPaths,
35	    status: VerificationStatus.SUBMITTED,
36	    submittedAt: new Date(),
37	    fileChecksums: input.fileChecksums,
38	  });
39	
40	  await logEvent({
41	    actorId: input.photographerId,
42	    action: AUDIT_EVENTS.KYC_SUBMIT,
43	    resource: 'verification',
44	    resourceId: verification._id.toString(),
45	    outcome: 'success',
46	  });
47	
48	  return verification;
49	}
50	
51	export interface AdminReviewInput {
52	  verificationId: string;
53	  reviewerId: string;
54	  decision: VerificationStatus.VERIFIED | VerificationStatus.REJECTED | VerificationStatus.NEEDS_CHANGES;
55	  reason: string;
56	}
57	
58	export async function adminReview(input: AdminReviewInput) {
59	  if (!input.reason || input.reason.trim().length === 0) {
60	    throw new ValidationError('A review reason is mandatory');
61	  }
62	
63	  const verification = await Verification.findById(input.verificationId);
64	  if (!verification) {
65	    throw new NotFoundError('Verification not found');
66	  }
67	
68	  if (
69	    verification.status !== VerificationStatus.SUBMITTED &&
70	    verification.status !== VerificationStatus.NEEDS_CHANGES
71	  ) {
72	    throw new ValidationError(
73	      `Cannot review a verification with status: ${verification.status}`
74	    );
75	  }
76	
77	  // Run compliance hook before approving
78	  if (input.decision === VerificationStatus.VERIFIED) {
79	    const complianceResult = await beforeVerificationApprove(verification.toObject());
80	    if (!complianceResult.allow) {
81	      throw new ForbiddenError(
82	        complianceResult.reason || 'Compliance check failed for verification approval'
83	      );
84	    }
85	  }
86	
87	  verification.status = input.decision;
88	  verification.reviewReason = input.reason;
89	  verification.reviewedBy = input.reviewerId as any;
90	  verification.reviewedAt = new Date();
91	  await verification.save();
92	
93	  const auditAction =
94	    input.decision === VerificationStatus.VERIFIED
95	      ? AUDIT_EVENTS.KYC_APPROVE
96	      : input.decision === VerificationStatus.REJECTED
97	        ? AUDIT_EVENTS.KYC_REJECT
98	        : AUDIT_EVENTS.KYC_REVIEW;
99	
100	  await logEvent({
101	    actorId: input.reviewerId,
102	    action: auditAction,
103	    resource: 'verification',
104	    resourceId: verification._id.toString(),
105	    details: { decision: input.decision, reason: input.reason },
106	    outcome: 'success',
107	  });
108	
109	  return verification;
110	}
111	
112	export async function getVerificationByPhotographer(photographerId: string) {
113	  const verification = await Verification.findOne({ photographerId }).sort({ submittedAt: -1 });
114	  if (!verification) {
115	    throw new NotFoundError('Verification not found');
116	  }
117	  return verification;
118	}
119	
120	export async function listPendingVerifications() {
121	  return Verification.find({
122	    status: { $in: [VerificationStatus.SUBMITTED, VerificationStatus.NEEDS_CHANGES] },
123	  }).sort({ submittedAt: 1 }).lean();
124	}
125	
126	/**
127	 * Get verification record. Non-admin viewers get masked identifiers.
128	 */
129	export async function getVerification(
130	  verificationId: string,
131	  viewerRole: Role
132	) {
133	  const verification = await Verification.findById(verificationId);
134	  if (!verification) {
135	    throw new NotFoundError('Verification not found');
136	  }
137	
138	  const obj = verification.toObject() as any;
139	
140	  if (viewerRole === Role.ADMIN) {
141	    // Decrypt for admin
142	    try {
143	      obj.realName = decrypt(obj.realName, 'government_id');
144	      obj.idDocumentPath = decrypt(obj.idDocumentPath, 'government_id');
145	      obj.qualificationDocPaths = obj.qualificationDocPaths.map(
146	        (p: string) => decrypt(p, 'qualification_documents')
147	      );
148	    } catch {
149	      // If decryption fails, return as-is
150	    }
151	  } else {
152	    // Mask identifiers for non-admin
153	    try {
154	      const decryptedName = decrypt(obj.realName, 'government_id');
155	      obj.realName = maskIdentifier(decryptedName);
156	    } catch {
157	      obj.realName = '***';
158	    }
159	    obj.idDocumentPath = '[REDACTED]';
160	    obj.qualificationDocPaths = obj.qualificationDocPaths.map(() => '[REDACTED]');
161	  }
162	
163	  return obj;
164	}
